When extended thinking is turned on, Claude creates:
1. `thinking` content blocks → internal reasoning
2. `text` content blocks → final answer

API response structure:
{
  "content": [
    {
      "type": "thinking",
      "thinking": "Let me analyze the database error...",
      "signature": "abc123..." // Digital signature for verification
    },
    {
      "type": "text",
      "text": "The database connection timed out. I'll try connecting to the backup server."
    }
  ]
}

{
  "thinking": {
    "type": "enabled",           // Enable extended thinking
    "budget_tokens": 5000        // Token budget for thinking (optional)
  },
  "max_tokens": 16000            // Total tokens (thinking + text)
}

const response = await client.messages.create({
  model: "claude-sonnet-4-5-20250929",
  max_tokens: 16000,
  thinking: { type: "enabled", budget_tokens: 5000 }, // Enable thinking
  tools: [queryDatabaseTool, fetchStockPriceTool],
  messages: [
    { role: "user", content: "Debug this database connection error and get stock price for AAPL" }
  ]
});

// Process interleaved thinking + tool calls
for (const block of response.content) {
  if (block.type === "thinking") {
    // Claude's reasoning process
    console.log(`Thinking: ${block.thinking}`);
    // "Let me analyze the database error. Timeout after 30s suggests..."
  } else if (block.type === "tool_use") {
    // Claude decided to call a tool after thinking
    console.log(`Tool: ${block.name}`, block.input);
    // "Tool: query_database { query: 'SELECT * FROM status' }"
  } else if (block.type === "text") {
    // Final answer after thinking + tool calls
    console.log(`Answer: ${block.text}`);
  }
}

// Level 1: "think" → ~4,000 tokens
const response1 = await client.messages.create({
  model: "claude-sonnet-4-5-20250929",
  thinking: { type: "enabled", budget_tokens: 4000 },
  messages: [{ role: "user", content: "think: Plan the architecture for this microservice" }]
});

// Level 2: "think hard" / "megathink" → ~10,000 tokens
const response2 = await client.messages.create({
  model: "claude-sonnet-4-5-20250929",
  thinking: { type: "enabled", budget_tokens: 10000 },
  messages: [{ role: "user", content: "think hard: Debug this complex multi-layer error" }]
});

// Level 3: "think harder" / "ultrathink" → ~31,999 tokens
const response3 = await client.messages.create({
  model: "claude-sonnet-4-5-20250929",
  thinking: { type: "enabled", budget_tokens: 31999 },
  messages: [{ role: "user", content: "think harder: Design scalable architecture for 10M users" }]
});

// Simple problems: smaller budget
const response1 = await client.messages.create({
  thinking: { type: "enabled", budget_tokens: 2000 }
});

// Complex problems: larger budget
const response2 = await client.messages.create({
  thinking: { type: "enabled", budget_tokens: 10000 }
});

// Monitor and adjust
console.log(`Thinking tokens used: ${response.thinking_tokens}`);

for (const block of response.content) {
  if (block.type === "thinking") {
    // Log thinking process for debugging
    console.log(`Thinking: ${block.thinking}`);
  } else if (block.type === "text") {
    // Final answer
    console.log(`Answer: ${block.text}`);
  }
}

const thinking_block = response.content[0];
const signature = thinking_block.signature;

// Use Anthropic's verification method
is_authentic = anthropic.verify_thinking(thinking_block.thinking, signature);

if (is_authentic) {
  console.log("Thinking content is authentic");
} else {
  console.log("Thinking content may be tampered");
}

// ✅ Good: Complex debugging scenario
const response = await client.messages.create({
  model: "claude-sonnet-4-5-20250929",
  thinking: { type: "enabled", budget_tokens: 5000 },
  tools: [queryDatabaseTool, fetchLogsTool],
  messages: [{
    role: "user",
    content: "Debug this multi-layer database error with connection timeout and slow queries"
  }]
});

// ❌ Bad: Simple query (no thinking needed)
const response2 = await client.messages.create({
  thinking: { type: "enabled", budget_tokens: 5000 },
  messages: [{ role: "user", content: "What's the weather?" }] // Simple query
});

// Step 1: Explore (gather context)
const explore = await client.messages.create({
  messages: [{ role: "user", content: "Explore the codebase structure" }]
});

// Step 2: Plan (use thinking mode)
const plan = await client.messages.create({
  thinking: { type: "enabled", budget_tokens: 4000 },
  messages: [{ role: "user", content: "think: Make a detailed plan for refactoring auth module" }]
});

// Step 3: Code (execute plan)
const code = await client.messages.create({
  tools: [writeFileTool],
  messages: [{ role: "user", content: `Implement plan: ${plan.text}` }]
});

// Step 4: Commit (finalize)
const commit = await client.messages.create({
  messages: [{ role: "user", content: "Commit the changes" }]
});

// Start with smaller budget for testing
const test = await client.messages.create({
  thinking: { type: "enabled", budget_tokens: 2000 }
});

// Adjust based on task complexity
